/**
 * SPEC-020: Capturas — flujo capture-first (listado global /captures).
 * Generated by QA Dev agent.
 *
 * Frontera de mocking: bridge window.api (el orden updatedAt desc y la
 * resolución de nombres vienen resueltos de main vía listAllInterviews, aquí
 * se asertan tal cual llegan). Lecciones aplicadas: toasts de sonner son <li>
 * y se duplican → getAllBy/findAllBy y nunca contar listitems globales; los
 * dialogs/sheets se abren desde el menú ⋯ con setTimeout(0) → findBy*;
 * scoping por fila con closest('li') porque los títulos y "Sin empresa" se
 * repiten entre filas y chips.
 */
import { render, screen, waitFor, within, type RenderResult } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { MemoryRouter, Route, Routes } from 'react-router-dom'
import { Toaster } from '@/components/ui/sonner'
import { TooltipProvider } from '@/components/ui/tooltip'
import { CapturesPage } from '@/pages/CapturesPage'
import type { CaptureListItem } from '@/types/captures'
import type { Contact, Discovery, Interview } from '@/types/domain'
import { installMockApi, type MockApiHandle } from '../../helpers/mockApi'

let mockApi: MockApiHandle

const DISCOVERY: Discovery = {
  id: 'd-1',
  name: 'Vertical Sanidad',
  createdAt: '2026-07-01T09:00:00.000Z',
  updatedAt: '2026-07-01T09:00:00.000Z'
}

const CONTACT: Contact = {
  id: 'ct-1',
  companyId: 'c-1',
  name: 'Jane Doe',
  position: null,
  linkedinUrl: null,
  createdAt: '2026-07-02T12:00:00.000Z',
  updatedAt: '2026-07-02T12:00:00.000Z'
}

function interview(overrides: Partial<Interview> = {}): Interview {
  return {
    id: 'i-1',
    discoveryId: 'd-1',
    companyId: null,
    contactId: null,
    templateId: null,
    title: 'Captura sin empresa',
    status: 'draft',
    scriptMarkdown: null,
    objectives: [],
    wavPath: null,
    transcriptPath: null,
    createdAt: '2026-07-10T10:00:00.000Z',
    updatedAt: '2026-07-10T10:00:00.000Z',
    ...overrides
  }
}

/** Captura sin empresa (capture-first), la más reciente. */
const UNASSIGNED: CaptureListItem = {
  interview: interview(),
  discoveryName: 'Vertical Sanidad',
  companyName: null,
  contactName: null,
  templateName: null
}

/** Entrevista creada por el flujo clásico de empresa (SPEC-013), más antigua. */
const ASSIGNED: CaptureListItem = {
  interview: interview({
    id: 'i-2',
    companyId: 'c-1',
    contactId: 'ct-1',
    templateId: 'tpl-1',
    title: 'Entrevista con Acme',
    status: 'recorded',
    updatedAt: '2026-07-09T10:00:00.000Z'
  }),
  discoveryName: 'Vertical Sanidad',
  companyName: 'Acme Corp',
  contactName: 'Jane Doe',
  templateName: 'Entrevista MDR'
}

function setCaptures(items: CaptureListItem[]): void {
  vi.mocked(mockApi.api.db.listAllInterviews).mockResolvedValue({ ok: true, data: items })
}

function renderCaptures(): RenderResult {
  return render(
    <TooltipProvider>
      <MemoryRouter initialEntries={['/captures']}>
        <Routes>
          <Route path="/captures" element={<CapturesPage />} />
          <Route path="/captures/:id" element={<div>CAPTURE_DETAIL_PROBE</div>} />
          <Route path="/discoveries" element={<div>DISCOVERIES_PROBE</div>} />
        </Routes>
      </MemoryRouter>
      <Toaster />
    </TooltipProvider>
  )
}

/** Fila de una captura, acotada por su título (el listado comparte textos entre filas). */
async function findCaptureRow(title: string): Promise<HTMLElement> {
  const link = await screen.findByRole('link', { name: title })
  const row = link.closest('li')
  if (row === null) {
    throw new Error('La captura debe renderizarse en una fila de lista propia')
  }
  return row
}

/** Abre el menú ⋯ de la fila y pulsa una acción (apertura diferida con setTimeout(0)). */
async function openRowAction(
  user: ReturnType<typeof userEvent.setup>,
  title: string,
  action: string
): Promise<void> {
  const row = await findCaptureRow(title)
  await user.click(within(row).getByRole('button', { name: 'Acciones' }))
  await user.click(await screen.findByRole('menuitem', { name: action }))
}

beforeEach(() => {
  vi.clearAllMocks()
  mockApi = installMockApi()
})

describe('CapturesPage', () => {
  describe('listing', () => {
    // SPEC-020 · AC-03 (listado global en el orden updatedAt desc resuelto por main)
    it('lists every interview in the system with title link, status badge and the muted refs row', async () => {
      setCaptures([UNASSIGNED, ASSIGNED])
      renderCaptures()

      // Ambas filas (con y sin empresa), en el orden que entrega main
      const list = await screen.findByTestId('captures-list')
      const rows = within(list).getAllByRole('listitem')
      expect(rows).toHaveLength(2)
      expect(within(rows[0]).getByRole('link', { name: 'Captura sin empresa' })).toHaveAttribute(
        'href',
        '/captures/i-1'
      )
      expect(within(rows[0]).getByText('Borrador')).toBeInTheDocument()
      expect(within(rows[0]).getByText('Vertical Sanidad')).toBeInTheDocument()
      // Fila con empresa: refs resueltas "{discovery} · {empresa} · {contacto} · {template}"
      expect(within(rows[1]).getByRole('link', { name: 'Entrevista con Acme' })).toBeInTheDocument()
      expect(within(rows[1]).getByText('Grabada')).toBeInTheDocument()
      expect(
        within(rows[1]).getByText('Vertical Sanidad · Acme Corp · Jane Doe · Entrevista MDR')
      ).toBeInTheDocument()
    })

    // SPEC-020 · AC-35 (las entrevistas del flujo de empresa entran en el listado global)
    it('navigates to /captures/:id when the title of a company-flow interview is clicked', async () => {
      setCaptures([UNASSIGNED, ASSIGNED])
      const user = userEvent.setup()
      renderCaptures()

      await user.click(await screen.findByRole('link', { name: 'Entrevista con Acme' }))

      expect(await screen.findByText('CAPTURE_DETAIL_PROBE')).toBeInTheDocument()
    })

    // SPEC-020 · AC-04
    it('renders "Sin empresa" as an outline badge only on rows without company', async () => {
      setCaptures([UNASSIGNED, ASSIGNED])
      renderCaptures()

      const unassignedRow = await findCaptureRow('Captura sin empresa')
      const badge = within(unassignedRow).getByText('Sin empresa')
      // Badge (variant outline), no texto muted: lo pendiente destaca
      expect(badge).toHaveAttribute('data-slot', 'badge')
      expect(badge).toHaveAttribute('data-variant', 'outline')

      const assignedRow = await findCaptureRow('Entrevista con Acme')
      expect(within(assignedRow).queryByText('Sin empresa')).not.toBeInTheDocument()
    })

    // SPEC-020 · AC-05
    it('filters to companyId-null captures with the "Sin empresa" chip and clears with "Limpiar filtros"', async () => {
      setCaptures([UNASSIGNED, ASSIGNED])
      const user = userEvent.setup()
      renderCaptures()
      await screen.findByRole('link', { name: 'Entrevista con Acme' })

      await user.click(screen.getByRole('button', { name: 'Sin empresa' }))

      expect(screen.getByRole('link', { name: 'Captura sin empresa' })).toBeInTheDocument()
      expect(screen.queryByRole('link', { name: 'Entrevista con Acme' })).not.toBeInTheDocument()
      // Con filtro activo aparece "Limpiar filtros" y restaura el listado completo
      await user.click(screen.getByRole('button', { name: 'Limpiar filtros' }))
      expect(await screen.findByRole('link', { name: 'Entrevista con Acme' })).toBeInTheDocument()
      expect(screen.queryByRole('button', { name: 'Limpiar filtros' })).not.toBeInTheDocument()
    })

    // SPEC-020 · AC-05 (refuerzo: empty por filtro del wireframe)
    it('shows the "No hay capturas sin empresa" filtered empty state when the filter matches nothing', async () => {
      setCaptures([ASSIGNED])
      const user = userEvent.setup()
      renderCaptures()
      await screen.findByRole('link', { name: 'Entrevista con Acme' })

      await user.click(screen.getByRole('button', { name: 'Sin empresa' }))

      const emptyText = await screen.findByText('No hay capturas sin empresa')
      // Con filtro activo y cero coincidencias hay DOS "Limpiar filtros"
      // legítimos (barra de filtros + empty state), ambos del wireframe
      expect(screen.getAllByRole('button', { name: 'Limpiar filtros' })).toHaveLength(2)
      const emptyState = emptyText.parentElement
      if (emptyState === null) {
        throw new Error('El empty por filtro debe renderizarse en su propio contenedor')
      }
      // El botón del EMPTY STATE limpia el filtro y restaura el listado
      await user.click(within(emptyState).getByRole('button', { name: 'Limpiar filtros' }))
      expect(await screen.findByRole('link', { name: 'Entrevista con Acme' })).toBeInTheDocument()
      expect(screen.queryByText('No hay capturas sin empresa')).not.toBeInTheDocument()
    })

    // SPEC-020 · AC-06
    it('shows the empty state with "Aún no hay capturas" and a working "Crear primera captura" CTA', async () => {
      setCaptures([])
      const user = userEvent.setup()
      renderCaptures()

      expect(await screen.findByText('Aún no hay capturas')).toBeInTheDocument()
      await user.click(screen.getByRole('button', { name: 'Crear primera captura' }))

      expect(await screen.findByTestId('new-capture-dialog')).toBeInTheDocument()
      expect(screen.getByRole('heading', { name: 'Nueva captura' })).toBeInTheDocument()
    })

    // SPEC-020 · AC-07
    it('shows the error state with the bridge message and recovers on "Reintentar"', async () => {
      vi.mocked(mockApi.api.db.listAllInterviews)
        .mockResolvedValueOnce({
          ok: false,
          error: { kind: 'storage', message: 'Fallo simulado del bridge' }
        })
        .mockResolvedValueOnce({ ok: true, data: [UNASSIGNED] })
      const user = userEvent.setup()
      renderCaptures()

      expect(await screen.findByText('Fallo simulado del bridge')).toBeInTheDocument()
      await user.click(screen.getByRole('button', { name: 'Reintentar' }))

      expect(await screen.findByRole('link', { name: 'Captura sin empresa' })).toBeInTheDocument()
    })

    // SPEC-020 · AC-08
    it('shows row skeletons while the list request is pending', async () => {
      vi.mocked(mockApi.api.db.listAllInterviews).mockReturnValue(
        new Promise(() => {
          // pendiente a propósito: el listado queda cargando
        })
      )
      const { container } = renderCaptures()

      await waitFor(() =>
        expect(container.querySelectorAll('[data-slot="skeleton"]').length).toBeGreaterThanOrEqual(
          3
        )
      )
      expect(screen.queryByText('Aún no hay capturas')).not.toBeInTheDocument()
    })
  })

  describe('creating a capture', () => {
    // SPEC-020 · AC-13
    it('creates the capture with discoveryId and companyId null, toasts "Captura creada" and navigates to its detail', async () => {
      setCaptures([])
      vi.mocked(mockApi.api.db.listDiscoveries).mockResolvedValue({
        ok: true,
        data: [DISCOVERY]
      })
      vi.mocked(mockApi.api.db.createInterview).mockResolvedValue({
        ok: true,
        data: interview({ id: 'i-9', title: 'Kickoff con prospecto' })
      })
      const user = userEvent.setup()
      renderCaptures()

      await user.click(await screen.findByRole('button', { name: 'Nueva captura' }))
      await screen.findByTestId('new-capture-dialog')
      await user.type(screen.getByLabelText('Título'), 'Kickoff con prospecto')
      await user.click(screen.getByRole('combobox', { name: 'Discovery' }))
      await user.click(await screen.findByRole('option', { name: 'Vertical Sanidad' }))
      await user.click(screen.getByRole('button', { name: 'Crear' }))

      // Capture-first: discovery obligatorio, empresa/contacto diferidos
      await waitFor(() =>
        expect(vi.mocked(mockApi.api.db.createInterview)).toHaveBeenCalledWith({
          discoveryId: 'd-1',
          companyId: null,
          title: 'Kickoff con prospecto',
          templateId: null
        })
      )
      expect((await screen.findAllByText('Captura creada')).length).toBeGreaterThanOrEqual(1)
      expect(await screen.findByText('CAPTURE_DETAIL_PROBE')).toBeInTheDocument()
    })
  })

  describe('row actions menu', () => {
    // SPEC-020 · AC-22
    it('offers "Asignar empresa y contacto" only on unassigned rows and opens the assign Sheet', async () => {
      setCaptures([UNASSIGNED, ASSIGNED])
      const user = userEvent.setup()
      renderCaptures()

      // Fila sin empresa: la acción existe y abre el Sheet de asignación
      await openRowAction(user, 'Captura sin empresa', 'Asignar empresa y contacto')
      expect(await screen.findByTestId('assign-company-sheet')).toBeInTheDocument()
      expect(
        screen.getByRole('heading', { name: 'Asignar empresa y contacto' })
      ).toBeInTheDocument()
      await user.keyboard('{Escape}')
      await waitFor(() =>
        expect(screen.queryByTestId('assign-company-sheet')).not.toBeInTheDocument()
      )

      // Fila con empresa: la acción no existe en su menú
      const assignedRow = await findCaptureRow('Entrevista con Acme')
      await user.click(within(assignedRow).getByRole('button', { name: 'Acciones' }))
      expect(await screen.findByRole('menuitem', { name: 'Editar' })).toBeInTheDocument()
      expect(
        screen.queryByRole('menuitem', { name: 'Asignar empresa y contacto' })
      ).not.toBeInTheDocument()
    })

    // SPEC-020 · AC-31 (Dialog de edición sin Contacto cuando no hay empresa)
    it('includes "Editar" and "Eliminar" in the menu and opens the edit dialog without a Contacto field for unassigned captures', async () => {
      setCaptures([UNASSIGNED])
      const user = userEvent.setup()
      renderCaptures()

      const row = await findCaptureRow('Captura sin empresa')
      await user.click(within(row).getByRole('button', { name: 'Acciones' }))
      expect(await screen.findByRole('menuitem', { name: 'Editar' })).toBeInTheDocument()
      expect(screen.getByRole('menuitem', { name: 'Eliminar' })).toBeInTheDocument()

      await user.click(screen.getByRole('menuitem', { name: 'Editar' }))

      expect(await screen.findByRole('heading', { name: 'Editar captura' })).toBeInTheDocument()
      expect(screen.getByLabelText('Título')).toHaveValue('Captura sin empresa')
      expect(screen.getByRole('combobox', { name: 'Plantilla' })).toBeInTheDocument()
      // Sin empresa no hay contacto que asignar desde la edición
      expect(screen.queryByRole('combobox', { name: 'Contacto' })).not.toBeInTheDocument()
    })

    // SPEC-020 · AC-31 (refuerzo: Contacto solo si la captura tiene empresa)
    it('includes the Contacto select preloaded in the edit dialog when the capture has a company', async () => {
      setCaptures([ASSIGNED])
      vi.mocked(mockApi.api.db.listContacts).mockResolvedValue({ ok: true, data: [CONTACT] })
      const user = userEvent.setup()
      renderCaptures()

      await openRowAction(user, 'Entrevista con Acme', 'Editar')

      expect(await screen.findByRole('heading', { name: 'Editar captura' })).toBeInTheDocument()
      const contactSelect = screen.getByRole('combobox', { name: 'Contacto' })
      // Precargado con el contacto actual de la captura (resuelto lazy)
      await waitFor(() => expect(contactSelect).toHaveTextContent('Jane Doe'))
      expect(vi.mocked(mockApi.api.db.listContacts)).toHaveBeenCalledWith('c-1')
    })

    // SPEC-020 · AC-32
    it('confirms deletion in the "Eliminar captura" AlertDialog with the exact copy and removes the row with its toast', async () => {
      setCaptures([UNASSIGNED, ASSIGNED])
      vi.mocked(mockApi.api.db.deleteInterview).mockResolvedValue({ ok: true, data: null })
      const user = userEvent.setup()
      renderCaptures()

      await openRowAction(user, 'Captura sin empresa', 'Eliminar')

      const dialog = await screen.findByRole('alertdialog')
      expect(
        within(dialog).getByRole('heading', { name: 'Eliminar captura' })
      ).toBeInTheDocument()
      expect(dialog).toHaveTextContent(
        'Se eliminarán permanentemente «Captura sin empresa» y sus notas.'
      )
      await user.click(within(dialog).getByRole('button', { name: 'Eliminar' }))

      expect(vi.mocked(mockApi.api.db.deleteInterview)).toHaveBeenCalledWith('i-1')
      await waitFor(() =>
        expect(screen.queryByRole('link', { name: 'Captura sin empresa' })).not.toBeInTheDocument()
      )
      expect((await screen.findAllByText('Captura eliminada')).length).toBeGreaterThanOrEqual(1)
      // La otra fila sobrevive
      expect(screen.getByRole('link', { name: 'Entrevista con Acme' })).toBeInTheDocument()
    })
  })
})
